const payload = $json;
const rows = Array.isArray(payload)
  ? payload
  : Array.isArray(payload.items)
    ? payload.items
    : Array.isArray(payload.tickets)
      ? payload.tickets
      : [];

const filtered = rows.filter((ticket) => {
  const status = String(ticket?.sla_status || '').trim().toLowerCase();
  return status === 'breached' || status === 'at_risk';
});

return filtered.map((ticket) => ({ json: ticket }));

const payload = {
  workflow: 'SLA Breach Alerting',
  channel: 'teams',
  timestamp: new Date().toISOString(),
  route: $json.error ? 'error' : 'ok',
  status: $json.statusCode || null,
  error: $json.error || null,
  response: $json.body || $json.data || null,
};
if (payload.route === 'error') {
  console.error('[n8n][sla-breach-alerting][teams]', JSON.stringify(payload));
} else {
  console.log('[n8n][sla-breach-alerting][teams]', JSON.stringify(payload));
}
return [{ json: payload }];

const message = {
  workflow: 'SLA Breach Alerting',
  when: new Date().toISOString(),
  error: $json.error || $json,
};
console.log('[n8n][error]', JSON.stringify(message));
return [{ json: message }];
